import math


def poly(xs: list, x: float):
    """
    Evaluates polynomial with coefficients xs at point x.
    return xs[0] + xs[1] * x + xs[1] * x^2 + .... xs[n] * x^n
    """
    return sum([coeff * math.pow(x, i) for i, coeff in enumerate(xs)])


def find_zero(xs: list):
    """ xs are coefficients of a polynomial.
    find_zero find x such that poly(x) = 0.
    find_zero returns only only zero point, even if there are many.
    Moreover, find_zero only takes list xs having even number of coefficients
    and largest non zero coefficient as it guarantees
    a solution.
    >>> round(find_zero([1, 2]), 2) # f(x) = 1 + 2x
    -0.5
    >>> round(find_zero([-6, 11, -6, 1]), 2) # (x - 1) * (x - 2) * (x - 3) = -6 + 11x - 6x^2 + x^3
    1.0
    """
    if not xs:
        raise ValueError("xs must not be empty")

    degree = len(xs) - 1
    while degree >= 0 and xs[degree] == 0:
        degree -= 1
    if degree < 0:
        raise ValueError("zero polynomial has infinitely many roots")

    if xs[0] == 0:
        return 0.0

    leading = xs[degree]

    def f(x):
        return poly(xs, x)

    bound = 1.0
    if degree % 2 == 1:
        if leading > 0:
            left, right = -bound, bound
            while f(left) > 0:
                bound *= 2
                left = -bound
            while f(right) < 0:
                bound *= 2
                right = bound
        else:
            left, right = -bound, bound
            while f(left) < 0:
                bound *= 2
                left = -bound
            while f(right) > 0:
                bound *= 2
                right = bound
    else:
        raise ValueError("Polynomial degree must be odd to guarantee a real root")

    fl = f(left)
    fr = f(right)

    if fl == 0:
        return float(left)
    if fr == 0:
        return float(right)

    for _ in range(200):
        mid = (left + right) / 2.0
        fm = f(mid)
        if abs(fm) < 1e-12 or abs(right - left) < 1e-12:
            return mid
        if fl * fm <= 0:
            right = mid
            fr = fm
        else:
            left = mid
            fl = fm

    return (left + right) / 2.0

